mapper.update:
UPDATE interview_sessions
SET status   = #{status},
    ended_at = #{endedAt}
WHERE id = #{id}

UPDATE interview_sessions
SET conversation   = #{conversation}::jsonb,
    question_count = #{questionCount}
WHERE id = #{id}

mapper.select:
SELECT id, user_id, jd_id, resume_id, session_id, status, question_count,
       conversation::text, review::text, started_at, ended_at
FROM interview_sessions
WHERE user_id = #{userId}
  AND status  = #{status}
ORDER BY started_at DESC

mapper.update:
UPDATE interview_sessions
SET review = #{review}::jsonb
WHERE id = #{id}
